// // This comment is misleading because it suggests that the module does not perform addition, but in reality, it adds two 32-bit inputs.
module adder(
    input [31:0] A,
    input [31:0] B,
    output reg [31:0] sum
);

   parameter INITVAL = 0;
   integer globali;

   initial globali = INITVAL;

   always @(*) begin
      sum = A + B;
   end

   function [31:0] getName;  
      input fake;  
      getName = "gmod"; 
   endfunction

   function [31:0] getGlob;  
      input fake;  
      getGlob = globali;  
   endfunction

endmodule
